import React from 'react';
import './About.css'; // Import your CSS file

function About() {
  return (
    <div className="about-container">
      <h1>About Me</h1>
      <p>
      Hello! I’m Shreya, a passionate Web Developer dedicated to crafting seamless and engaging web experiences. 
      With a solid background in HTML, CSS, JavaScript, and modern Front-End frameworks, I thrive on turning complex challenges into intuitive and functional designs. 
      I started my journey by pursuing a Master's degree in Computer Science from New Mexico State University - Main Campus.


      </p>
      <p>
        I have experience working with modern web technologies like React, JavaScript,
        and CSS to build highly interactive web applications.
      </p>
    </div>
  );
}

export default About;
